import FileUploader from "@/components/FileUploader";
import ExportButton from "@/components/ExportButton";
import { api, getApiErrorMessage } from "@/lib/api";

const ModuleB = () => {
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [uploadedDocuments, setUploadedDocuments] = useState([]);
  const [extractedData, setExtractedData] = useState(null);
  const [currentDocumentId, setCurrentDocumentId] = useState(null);
  const [costCenters, setCostCenters] = useState([]);
  const [showAssignModal, setShowAssignModal] = useState(false);
  const [selectedLine, setSelectedLine] = useState(null);
  const [assignments, setAssignments] = useState([]);

  useEffect(() => {
    fetchCostCenters();
  }, []);

  const fetchCostCenters = async () => {
    try {
      const response = await api.get("/cost-centers/");
      setCostCenters(response.data);
    } catch (error) {
      console.error("Error fetching cost centers:", error);
      toast.error(getApiErrorMessage(error, "Error al cargar los centros de costo"));
    }
  };

  const fetchAssignments = async (documentId) => {
    try {
      const response = await api.get(`/assignments?document_id=${documentId}`);
      setAssignments(response.data);
    } catch (error) {
      console.error("Error fetching assignments:", error);
      toast.error(getApiErrorMessage(error, "Error al cargar las asignaciones"));
    }
  };

  const handleUpload = async () => {
    if (selectedFiles.length === 0) {
      toast.error("Por favor selecciona al menos un archivo.");
      return;
    }

    setUploading(true);
    try {
      const formData = new FormData();
      selectedFiles.forEach((file) => formData.append("files", file));

      const response = await api.post("/documents/upload", formData);
      setUploadedDocuments(response.data);
      setExtractedData(null);
      setAssignments([]);
      setCurrentDocumentId(null);
      toast.success(`${response.data.length} archivo(s) subido(s) exitosamente.`);
    } catch (error) {
      console.error("Error uploading:", error);
      toast.error(getApiErrorMessage(error, "Error al subir archivos"));
    } finally {
      setUploading(false);
    }
  };

  const handleProcess = async (documentId) => {
    setProcessing(true);
    setCurrentDocumentId(documentId);
    setExtractedData(null);

    try {
      const formData = new FormData();
      formData.append("module_type", "specialized");

      const response = await api.post(`/documents/${documentId}/process`, formData);
      setExtractedData(response.data.data);
      await fetchAssignments(documentId);
      toast.success("Documento procesado exitosamente.");
    } catch (error) {
      console.error("Error processing:", error);
      toast.error(getApiErrorMessage(error, "Error al procesar el documento"));
    } finally {
      setProcessing(false);
    }
  };

  const handleAssignLine = async (lineType, lineIndex, lineData, costCenterId) => {
    try {
      await api.post("/assignments", {
        document_id: currentDocumentId,
        line_type: lineType,
        line_index: lineIndex,
        line_identifier: lineData.numero_movil || lineData.descripcion || null,
        cost_center_id: costCenterId,
        monto_bs: Number(lineData.monto_bs || 0),
      });

      await fetchAssignments(currentDocumentId);
      setShowAssignModal(false);
      setSelectedLine(null);
      toast.success("Linea asignada exitosamente.");
    } catch (error) {
      console.error("Error assigning line:", error);
      toast.error(getApiErrorMessage(error, "Error al asignar la linea"));
    }
  };

  const openAssignModal = (lineType, lineIndex, item) => {
    setSelectedLine({ ...item, lineType, lineIndex });
    setShowAssignModal(true);
  };

  const renderAssignmentCell = (lineType, index, item) => {
    const assignment = assignments.find(
      (entry) => entry.line_type === lineType && entry.line_index === index
    );

    if (assignment) {
      return (
        <span className="px-2 py-1 text-xs font-bold uppercase tracking-wider border rounded-none text-green-700 border-green-700 bg-green-50">
          {assignment.cost_center_name}
        </span>
      );
    }

    return (
      <button
        onClick={() => openAssignModal(lineType, index, item)}
        data-testid={`assign-${lineType}-${index}`}
        className="text-[#0033CC] hover:underline text-sm font-medium"
      >
        Asignar centro de costo
      </button>
    );
  };

  const sections = [
    {
      key: "ventas_terceros",
      title: "Ventas de terceros",
      columns: ["Descripcion", "Cantidad", "Monto en Bs", "Centro de costo"],
      rows: extractedData?.ventas_terceros || [],
      renderRow: (item, index) => (
        <tr key={`ventas-${index}`}>
          <td>{item.descripcion || "-"}</td>
          <td className="font-mono">{item.cantidad ?? "-"}</td>
          <td className="font-mono">
            {item.monto_bs != null ? Number(item.monto_bs).toLocaleString() : "-"}
          </td>
          <td>{renderAssignmentCell("ventas_terceros", index, item)}</td>
        </tr>
      ),
    },
    {
      key: "telefonia_movil",
      title: "Telefonia movil",
      columns: ["No. movil", "Descripcion", "Monto en Bs", "Centro de costo"],
      rows: extractedData?.telefonia_movil || [],
      renderRow: (item, index) => (
        <tr key={`movil-${index}`}>
          <td className="font-mono">{item.numero_movil || "-"}</td>
          <td>{item.descripcion || "-"}</td>
          <td className="font-mono">
            {item.monto_bs != null ? Number(item.monto_bs).toLocaleString() : "-"}
          </td>
          <td>{renderAssignmentCell("telefonia_movil", index, item)}</td>
        </tr>
      ),
    },
    {
      key: "rentas_servicios",
      title: "Rentas y servicios",
      columns: ["Descripcion", "Fecha desde", "Fecha hasta", "Monto en Bs", "Centro de costo"],
      rows: extractedData?.rentas_servicios || [],
      renderRow: (item, index) => (
        <tr key={`rentas-${index}`}>
          <td>{item.descripcion || "-"}</td>
          <td>{item.fecha_desde || "-"}</td>
          <td>{item.fecha_hasta || "-"}</td>
          <td className="font-mono">
            {item.monto_bs != null ? Number(item.monto_bs).toLocaleString() : "-"}
          </td>
          <td>{renderAssignmentCell("rentas_servicios", index, item)}</td>
        </tr>
      ),
    },
    {
      key: "resumen_consumo",
      title: "Resumen de consumo",
      columns: ["Descripcion", "Unidades consumidas", "Monto en Bs", "Centro de costo"],
      rows: extractedData?.resumen_consumo || [],
      renderRow: (item, index) => (
        <tr key={`resumen-${index}`}>
          <td>{item.descripcion || "-"}</td>
          <td className="font-mono">{item.unidades_consumidas ?? "-"}</td>
          <td className="font-mono">
            {item.monto_bs != null ? Number(item.monto_bs).toLocaleString() : "-"}
          </td>
          <td>{renderAssignmentCell("resumen_consumo", index, item)}</td>
        </tr>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="bg-white border border-zinc-200 rounded-none p-6">
        <h2 className="font-heading text-2xl font-bold text-[#09090B] mb-2 tracking-tight">
          Modulo B: Analisis Especializado
        </h2>
        <p className="text-zinc-600">
          Procesa documentos complejos con tablas de ventas de terceros, telefonia
          movil, rentas y servicios, y resumen de consumo.
        </p>
      </div>

      <div className="bg-white border border-zinc-200 rounded-none p-6">
        <h3 className="font-heading text-lg font-bold text-[#09090B] mb-4 tracking-tight">
          1. Cargar documentos
        </h3>
        <FileUploader onFilesSelected={setSelectedFiles} />
        {selectedFiles.length > 0 && (
          <button
            onClick={handleUpload}
            disabled={uploading}
            data-testid="upload-button-module-b"
            className="mt-4 bg-[#0033CC] text-white rounded-none px-6 py-2 font-medium hover:bg-[#002299] transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {uploading ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Subiendo...
              </>
            ) : (
              "Subir archivos"
            )}
          </button>
        )}
      </div>

      {uploadedDocuments.length > 0 && (
        <div className="bg-white border border-zinc-200 rounded-none p-6">
          <h3 className="font-heading text-lg font-bold text-[#09090B] mb-4 tracking-tight">
            2. Procesar con IA
          </h3>
          <div className="space-y-2">
            {uploadedDocuments.map((doc) => (
              <div
                key={doc.id}
                data-testid={`document-b-${doc.id}`}
                className="flex items-center justify-between p-4 border border-zinc-200 rounded-none"
              >
                <div>
                  <p className="font-medium text-zinc-900">{doc.filename}</p>
                  <p className="text-sm text-zinc-500">
                    {(Number(doc.file_size || 0) / 1024).toFixed(2)} KB
                  </p>
                </div>
                <button
                  onClick={() => handleProcess(doc.id)}
                  disabled={processing}
                  data-testid={`process-button-b-${doc.id}`}
                  className="bg-transparent border border-zinc-300 text-zinc-900 rounded-none px-6 py-2 font-medium hover:bg-zinc-100 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {processing && currentDocumentId === doc.id ? (
                    <span className="flex items-center gap-2">
                      <Loader2 className="w-4 h-4 animate-spin" />
                      Procesando...
                    </span>
                  ) : (
                    "Procesar"
                  )}
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {extractedData && (
        <div className="space-y-6">
          {sections
            .filter((section) => section.rows.length > 0)
            .map((section) => (
              <div
                key={section.key}
                className="bg-white border border-zinc-200 rounded-none p-6"
              >
                <h3 className="font-heading text-lg font-bold text-[#09090B] mb-4 tracking-tight">
                  {section.title}
                </h3>
                <div className="overflow-x-auto">
                  <table className="w-full" data-testid={`${section.key}-table`}>
                    <thead>
                      <tr className="bg-zinc-50">
                        {section.columns.map((column) => (
                          <th key={column} className="text-left">
                            {column}
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>{section.rows.map(section.renderRow)}</tbody>
                  </table>
                </div>
              </div>
            ))}

          <div className="bg-white border border-zinc-200 rounded-none p-6">
            <ExportButton
              documentId={currentDocumentId}
              exportType="specialized"
              label="Exportar analisis completo a Excel"
            />
          </div>
        </div>
      )}

      {showAssignModal && selectedLine && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"
          data-testid="assign-modal"
        >
          <div className="bg-white border border-zinc-200 rounded-none p-6 max-w-md w-full mx-4">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-heading text-lg font-bold text-[#09090B]">
                Asignar centro de costo
              </h3>
              <button
                onClick={() => {
                  setShowAssignModal(false);
                  setSelectedLine(null);
                }}
                data-testid="close-assign-modal"
                className="text-zinc-400 hover:text-zinc-900"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <p className="text-sm text-zinc-600 mb-4">
              {selectedLine.numero_movil
                ? `Numero movil: ${selectedLine.numero_movil}`
                : `Descripcion: ${selectedLine.descripcion || "-"}`}
            </p>

            <div className="space-y-2">
              {costCenters.map((costCenter) => (
                <button
                  key={costCenter.id}
                  onClick={() =>
                    handleAssignLine(
                      selectedLine.lineType,
                      selectedLine.lineIndex,
                      selectedLine,
                      costCenter.id
                    )
                  }
                  data-testid={`select-cost-center-${costCenter.id}`}
                  className="w-full text-left p-3 border border-zinc-200 rounded-none hover:border-[#0033CC] hover:bg-zinc-50 transition-colors"
                >
                  <p className="font-medium text-zinc-900">{costCenter.name}</p>
                  {costCenter.description && (
                    <p className="text-sm text-zinc-500">{costCenter.description}</p>
                  )}
                </button>
              ))}

              {costCenters.length === 0 && (
                <p className="text-sm text-zinc-500 text-center py-4">
                  No hay centros de costo disponibles. Crea uno primero.
                </p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ModuleB;
